 1→package auth
 2→
 3→import (
 4→	"errors"
 5→	"fmt"
 6→
 7→	"github.com/golang-jwt/jwt/v5"
 8→	"github.com/google/uuid"
 9→)
10→
11→// Claims extends jwt.RegisteredClaims with application-specific fields.
12→type Claims struct {
13→	jwt.RegisteredClaims
14→	UserID     uuid.UUID `json:"uid"`
15→	Email      string    `json:"email,omitempty"`
16→	ClientType string    `json:"ctype,omitempty"` // web|cli|mobile
17→}
18→
19→// Validator validates a JWT token string and returns parsed claims.
20→type Validator interface {
21→	Validate(tokenString string) (*Claims, error)
22→}
23→
24→// HMACValidator validates HS256 tokens using a shared secret.
25→type HMACValidator struct {
26→	secret []byte
27→}
28→
29→// NewHMACValidator creates a Validator using HS256 with the provided secret.
30→func NewHMACValidator(secret string) *HMACValidator {
31→	return &HMACValidator{secret: []byte(secret)}
32→}
33→
34→// Validate parses and validates an HS256 JWT token string.
35→func (v *HMACValidator) Validate(tokenString string) (*Claims, error) {
36→	claims := &Claims{}
37→	token, err := jwt.ParseWithClaims(tokenString, claims, func(t *jwt.Token) (any, error) {
38→		if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
39→			return nil, fmt.Errorf("auth: unexpected signing method: %v", t.Header["alg"])
40→		}
41→		return v.secret, nil
42→	})
43→	if err != nil {
44→		return nil, fmt.Errorf("auth: token validation failed: %w", err)
45→	}
46→	if !token.Valid {
47→		return nil, errors.New("auth: token is not valid")
48→	}
49→	return claims, nil
50→}
51→

 1→package middleware
 2→
 3→import (
 4→	"net"
 5→	"net/http"
 6→	"sync"
 7→	"time"
 8→
 9→	"golang.org/x/time/rate"
10→)
11→
12→// RateLimiter provides per-IP rate limiting using an in-memory token bucket.
13→type RateLimiter struct {
14→	mu       sync.Mutex
15→	visitors map[string]*visitor
16→	limit    rate.Limit
17→	burst    int
18→}
19→
20→type visitor struct {
21→	limiter  *rate.Limiter
22→	lastSeen time.Time
23→}
24→
25→// NewRateLimiter creates a rate limiter that allows requestsPerMinute requests
26→// per IP address. A background goroutine cleans up stale entries.
27→func NewRateLimiter(requestsPerMinute int) *RateLimiter {
28→	rl := &RateLimiter{
29→		visitors: make(map[string]*visitor),
30→		limit:    rate.Limit(float64(requestsPerMinute) / 60.0),
31→		burst:    max(requestsPerMinute/10, 1),
32→	}
33→	go rl.cleanup()
34→	return rl
35→}
36→
37→// Limit returns middleware that enforces the rate limit per client IP.
38→func (rl *RateLimiter) Limit(next http.Handler) http.Handler {
39→	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
40→		ip := clientIP(r)
41→		limiter := rl.getVisitor(ip)
42→		if !limiter.Allow() {
43→			http.Error(w, http.StatusText(http.StatusTooManyRequests), http.StatusTooManyRequests)
44→			return
45→		}
46→		next.ServeHTTP(w, r)
47→	})
48→}
49→
50→func (rl *RateLimiter) getVisitor(ip string) *rate.Limiter {
51→	rl.mu.Lock()
52→	defer rl.mu.Unlock()
53→
54→	v, exists := rl.visitors[ip]
55→	if !exists {
56→		limiter := rate.NewLimiter(rl.limit, rl.burst)
57→		rl.visitors[ip] = &visitor{limiter: limiter, lastSeen: time.Now()}
58→		return limiter
59→	}
60→	v.lastSeen = time.Now()
61→	return v.limiter
62→}
63→
64→func (rl *RateLimiter) cleanup() {
65→	for {
66→		time.Sleep(time.Minute)
67→		rl.mu.Lock()
68→		for ip, v := range rl.visitors {
69→			if time.Since(v.lastSeen) > 3*time.Minute {
70→				delete(rl.visitors, ip)
71→			}
72→		}
73→		rl.mu.Unlock()
74→	}
75→}
76→
77→func clientIP(r *http.Request) string {
78→	// chi's RealIP middleware sets RemoteAddr to the real client IP,
79→	// so we just strip the port if present.
80→	host, _, err := net.SplitHostPort(r.RemoteAddr)
81→	if err != nil {
82→		return r.RemoteAddr
83→	}
84→	return host
85→}
