		qb.add("sensitivity = ANY($%d)", f.Sensitivity)
	}
	if len(f.Tags) > 0 {
		qb.add("tags && $%d", f.Tags)
	}
	if f.Source != nil {
		qb.add("source = $%d", *f.Source)
	}
	if f.DateFrom != nil {
		qb.add("created_at >= $%d", *f.DateFrom)
	}
	if f.DateTo != nil {
