package item

import (
	"testing"
	"time"

	"github.com/google/uuid"
)

func TestQueryBuilderAdd(t *testing.T) {
	qb := &queryBuilder{}
	qb.add("owner_id = $%d", uuid.New())
	qb.add("type = $%d", "bookmark")

	if len(qb.conditions) != 2 {
		t.Fatalf("expected 2 conditions, got %d", len(qb.conditions))
	}
	if qb.conditions[0] != "owner_id = $1" {
		t.Errorf("expected 'owner_id = $1', got %q", qb.conditions[0])
	}
	if qb.conditions[1] != "type = $2" {
		t.Errorf("expected 'type = $2', got %q", qb.conditions[1])
	}
	if len(qb.args) != 2 {
		t.Fatalf("expected 2 args, got %d", len(qb.args))
	}
}

func TestQueryBuilderWhere(t *testing.T) {
	t.Run("empty", func(t *testing.T) {
		qb := &queryBuilder{}
		if got := qb.where(); got != "" {
			t.Errorf("expected empty string, got %q", got)
		}
	})

	t.Run("single condition", func(t *testing.T) {
		qb := &queryBuilder{}
		qb.add("owner_id = $%d", uuid.New())
		want := "WHERE owner_id = $1"
		if got := qb.where(); got != want {
			t.Errorf("expected %q, got %q", want, got)
		}
	})

	t.Run("multiple conditions", func(t *testing.T) {
		qb := &queryBuilder{}
		qb.add("owner_id = $%d", uuid.New())
		qb.add("type = $%d", "bookmark")
		want := "WHERE owner_id = $1 AND type = $2"
		if got := qb.where(); got != want {
			t.Errorf("expected %q, got %q", want, got)
		}
	})
}

func TestQueryBuilderNextParam(t *testing.T) {
	qb := &queryBuilder{}
	if got := qb.nextParam(); got != 1 {
		t.Errorf("expected 1, got %d", got)
	}
	qb.add("x = $%d", "val")
	if got := qb.nextParam(); got != 2 {
		t.Errorf("expected 2, got %d", got)
	}
}

func TestSortFieldToColumn(t *testing.T) {
	tests := []struct {
		input   string
		wantCol string
		wantOK  bool
	}{
		{"CREATED_AT", "created_at", true},
		{"UPDATED_AT", "updated_at", true},
		{"CAPTURED_AT", "captured_at", true},
		{"TITLE", "title", true},
		{"created_at", "created_at", true},
		{"INVALID", "", false},
		{"", "", false},
	}
	for _, tt := range tests {
		col, ok := sortFieldToColumn(tt.input)
		if col != tt.wantCol || ok != tt.wantOK {
			t.Errorf("sortFieldToColumn(%q) = (%q, %v), want (%q, %v)",
				tt.input, col, ok, tt.wantCol, tt.wantOK)
		}
	}
}

func TestSortDirectionSQL(t *testing.T) {
	tests := []struct {
		input string
