package resolver

import (
	"context"
	"testing"
	"time"

	"github.com/google/uuid"

	"github.com/ketang/flotsam/api/graph/model"
	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/item"
)

func TestRequireAuth(t *testing.T) {
	t.Run("no claims returns error", func(t *testing.T) {
		_, err := requireAuth(context.Background())
		if err == nil {
			t.Fatal("expected error")
		}
		if err != errAuthRequired {
			t.Errorf("expected errAuthRequired, got %v", err)
		}
	})

	t.Run("with claims succeeds", func(t *testing.T) {
		claims := &auth.Claims{UserID: uuid.New(), Email: "test@example.com"}
		ctx := auth.WithClaims(context.Background(), claims)
		got, err := requireAuth(ctx)
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if got.UserID != claims.UserID {
			t.Errorf("expected UserID %v, got %v", claims.UserID, got.UserID)
		}
	})
}

func TestToGraphQLItem(t *testing.T) {
	title := "Test Title"
	contentText := "Some content"
	contentURL := "https://example.com"
	sourceURL := "https://referrer.com"
	now := time.Now().UTC().Truncate(time.Millisecond)

	it := &item.Item{
		ID:           uuid.New(),
		OwnerID:      uuid.New(),
		Type:         "bookmark",
		Status:       "ready",
		Sensitivity:  "normal",
		Title:        &title,
		ContentText:  &contentText,
		ContentURL:   &contentURL,
		Tags:         []string{"go", "test"},
		Metadata:     map[string]any{"key": "val"},
		AutoMetadata: map[string]any{"auto": true},
		Source:       "chrome_extension",
		SourceURL:    &sourceURL,
		CreatedAt:    now,
		UpdatedAt:    now,
		CapturedAt:   now,
	}

	result := toGraphQLItem(it)

	if result.ID != it.ID.String() {
		t.Errorf("ID mismatch: %s vs %s", result.ID, it.ID.String())
	}
	if result.Type != model.ItemTypeBookmark {
		t.Errorf("Type = %v, want BOOKMARK", result.Type)
	}
	if result.Status != model.ItemStatusReady {
		t.Errorf("Status = %v, want READY", result.Status)
	}
	if result.Sensitivity != model.SensitivityLevelNormal {
		t.Errorf("Sensitivity = %v, want NORMAL", result.Sensitivity)
	}
	if *result.Title != title {
		t.Errorf("Title = %v, want %v", *result.Title, title)
	}
	if *result.ContentText != contentText {
		t.Errorf("ContentText mismatch")
	}
	if *result.ContentURL != contentURL {
		t.Errorf("ContentURL mismatch")
	}
	if len(result.Tags) != 2 {
		t.Errorf("Tags length = %d, want 2", len(result.Tags))
	}
	if result.Source != "chrome_extension" {
		t.Errorf("Source = %q, want 'chrome_extension'", result.Source)
	}
	if *result.SourceURL != sourceURL {
		t.Errorf("SourceURL mismatch")
	}
	if !result.CreatedAt.Equal(now) {
		t.Errorf("CreatedAt mismatch")
	}
}

func TestToGraphQLItemNilFields(t *testing.T) {
	it := &item.Item{
		ID:          uuid.New(),
		OwnerID:     uuid.New(),
		Type:        "text_note",
		Status:      "pending",
		Sensitivity: "public",
		Source:      "api",
		CreatedAt:   time.Now(),
		UpdatedAt:   time.Now(),
		CapturedAt:  time.Now(),
	}

	result := toGraphQLItem(it)

	if result.Title != nil {
		t.Error("expected nil Title")
	}
	if result.ContentText != nil {
		t.Error("expected nil ContentText")
	}
	if len(result.Tags) != 0 {
